<fieldset class="frequency-options">
    <legend class="sr-only">
        How often would you like to donate?
    </legend>
    <ul>
        <li>
            <input type="radio" name="frequency" id="frequency_onetime" value="onetime" onclick="donationForm.setFrequency('onetime');" checked="">
            <label class="frb-btn" for="frequency_onetime">Once</label>
        </li>
        <li>
            <input type="radio" name="frequency" id="frequency_monthly" value="monthly" onclick="donationForm.setFrequency('monthly');">
            <label class="frb-btn" for="frequency_monthly">Monthly</label>
        </li>
        <li style="display: block;">
            <input type="radio" name="frequency" id="frequency_annual" value="annual" onclick="donationForm.setFrequency('annual');">
            <label class="frb-btn" for="frequency_annual">Yearly</label>
        </li>
    </ul>
</fieldset>
<fieldset class="amount-options">
    <legend class="sr-only">
        Donation amount (EUR)
    </legend>
    <ul>
        <li class="radiobuttons-cell input_amount_0">
            <input type="radio" name="amount" id="input_amount_0" onclick="selectAmount();" value="2.50">
            <label class="frb-btn" for="input_amount_0">€2.50</label>
        </li>
        <li class="radiobuttons-cell input_amount_1">
            <input type="radio" name="amount" id="input_amount_1" onclick="selectAmount();" value="5">
            <label class="frb-btn" for="input_amount_1">€5</label>
        </li>
        <li class="radiobuttons-cell input_amount_2">
            <input type="radio" name="amount" id="input_amount_2" onclick="selectAmount();" value="10">
            <label class="frb-btn" for="input_amount_2">€10</label>
        </li>
        <li class="radiobuttons-cell input_amount_3">
            <input type="radio" name="amount" id="input_amount_3" onclick="selectAmount();" value="20">
            <label class="frb-btn" for="input_amount_3">€20</label>
        </li> 
        <li class="radiobuttons-cell input_amount_4">
            <input type="radio" name="amount" id="input_amount_4" onclick="selectAmount();" value="30">
            <label class="frb-btn" for="input_amount_4">€30</label>
        </li>
        <li class="radiobuttons-cell input_amount_5">
            <input type="radio" name="amount" id="input_amount_5" onclick="selectAmount();" value="50">
            <label class="frb-btn" for="input_amount_5">€50</label>
        </li>
        <li class="radiobuttons-cell input_amount_6">
            <input type="radio" name="amount" id="input_amount_6" onclick="selectAmount();" value="100">
            <label class="frb-btn" for="input_amount_6">€100</label>
        </li>
        <li class="radiobuttons-cell input_amount_other">
            <input type="radio" name="amount" id="input_amount_other" value="Other" onclick="document.getElementById('input_amount_other_box').focus();">
            <label class="frb-btn" for="input_amount_other">
                <span>Other</span>
                <input id="input_amount_other_box" type="text" inputmode="decimal" autocomplete="off" value="" tabindex="-1" class="noime" onfocus="selectOther();">
            </label>
        </li>
    </ul>
    <!-- tabindex="-1" allows focus with js so errors can be announced -->
    <div style="display: none;" tabindex="-1" class="lp-error lp-error-smallamount">
        Please select an amount (minimum 0,87&nbsp;EUR)
    </div>
    <div style="display: none;" tabindex="-1" class="lp-error lp-error-bigamount">
        We cannot accept donations greater than USD 25.000 (21.692 EUR) through our website. Please contact our major gifts staff at benefactors@wikimedia.org.
    </div>
<div class="ptf">
    <div class="lp-checkbox-wrapper">
